// Loop for adding array elements to a collection → Collections.addAll
for (int $i = 0; $i < $array.length; $i++) {
    $collection.add($array[$i]);
}
=>
java.util.Collections.addAll($collection, $array)
;;

// Hypothetical DSL rule (requires significant language extension)
// Matches two or three consecutive catch blocks with identical body
catch ($Type1 $e) { $body$ } catch ($Type2 $e2) { $body$ } :: $e == $e2 && $body$ == $body$
=> catch ($Type1 | $Type2 $e) { $body$ }
;;

